import ldap3

def search_user_by_username(ldap_server, ldap_port, base_dn, username, user_password):
    try:
        # Connect to the LDAP server
        server = ldap3.Server(ldap_server, port=ldap_port, get_info=ldap3.ALL)
        conn = ldap3.Connection(server, user=f"cn=admin,dc=example,dc=com", password=user_password, auto_bind=True)

        # Search for the user by username
        search_filter = f"(uid={username})"
        attributes = ['uid', 'cn', 'mail']
        conn.search(base_dn, search_filter, attributes=attributes)

        if conn.entries:
            return conn.entries[0]
        else:
            return None

    except ldap3.core.exceptions.LDAPException as e:
        print(f"LDAP error: {e}")
        return None
    finally:
        # Close the connection
        if conn and conn.bound:
            conn.unbind()

